def divide_numbers(a, b):
    """Divides two numbers with exception handling."""
    try:
        result = a / b
        print(f"Result: {result}")
    except ZeroDivisionError:
        print("Error: Cannot divide by zero!")
    except ValueError:
        print("Error: Invalid value provided!")
    except Exception as e:
        print(f"Unexpected error: {e}")

# Test cases
divide_numbers(10, 2)    # Normal case
divide_numbers(10, 0)    # ZeroDivisionError
divide_numbers(10, "2")  # TypeError (inherits from Exception)

def read_integer(prompt):
    """Reads and validates integer input using comprehensive exception handling."""
    while True:
        try:
            user_input = input(prompt)
            if not user_input.strip():
                raise ValueError("Input cannot be empty")
            number = int(user_input)
        except ValueError as e:
            print(f"Invalid input: {e}")
            if input("Try again? (y/n): ").lower() != 'y':
                break
        else:
            print(f"Successfully parsed: {number}")
            return number
        finally:
            print("Attempt complete (finally block executed)")

# Test the function
result = read_integer("Enter a number: ")
print(f"Final result: {result}")

# Custom Exception Class
class InvalidAgeError(Exception):
    """Custom exception for invalid age values."""
    def __init__(self, age, message="Age must be between 0 and 150"):
        self.age = age
        self.message = message
        super().__init__(self.message)

# Context Manager Class
class FileValidator:
    """Context manager for safe file operations with validation."""
    def __init__(self, filename):
        self.filename = filename
        self.file = None

    def __enter__(self):
        try:
            self.file = open(self.filename, 'r')
            content = self.file.read()
            if not content:
                raise ValueError("File is empty")
            return content
        except FileNotFoundError:
            raise FileNotFoundError(f"File '{self.filename}' not found")

    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.file:
            self.file.close()
        # Return True to suppress exceptions, False to propagate
        return False

# Using custom exception
def set_age(age):
    if not isinstance(age, int) or age < 0 or age > 150:
        raise InvalidAgeError(age)
    return f"Age set to {age}"

# Test cases
try:
    print(set_age(25))
except InvalidAgeError as e:
    print(f"Custom error caught: {e.age} - {e.message}")

try:
    print(set_age(200))
except InvalidAgeError as e:
    print(f"Custom error caught: {e.age} - {e.message}")

# Using context manager
try:
    with FileValidator("nonexistent.txt") as content:
        print(content)
except FileNotFoundError as e:
    print(f"Context manager error: {e}")
